#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Diagnose + accelerate source ingestion: inspect the generic collector's batch logic,
force passes over the WIRED backlog, and report how many sources newly pull rows + which
stay empty (dead). Informs the parallelization fix. exit-0-safe."""
import os,sys,json,time,subprocess,random
def sh(c,t=110):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "TO/ERR"
def psql(q,t=25):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR:"+r.stderr.strip()[:90])
G="/opt/atlas/importers/atlas_socrata_generic.py"
out={"kind":"srcpull","ts":int(time.time())}
try:
    out["collector_logic"]=sh("grep -nE 'WIRED|LIMIT|BATCH|batch|for |claim|SKIP LOCKED|def main|--loop|max_|per_run|source_catalog|order by' %s 2>/dev/null | head -22"%G)
    out["sources_with_rows_before"]=psql("SELECT count(DISTINCT source_code) FROM atlas.source_record")
    biz0=psql("SELECT reltuples::bigint FROM pg_class WHERE relname='business'")
    # force 2 collector passes
    out["run1"]=sh("cd /opt/atlas && timeout 95 /opt/atlas/venv/bin/python %s 2>&1 | tail -8"%G, t=105)
    out["run2"]=sh("cd /opt/atlas && timeout 95 /opt/atlas/venv/bin/python %s 2>&1 | tail -8"%G, t=105)
    out["sources_with_rows_after"]=psql("SELECT count(DISTINCT source_code) FROM atlas.source_record")
    biz1=psql("SELECT reltuples::bigint FROM pg_class WHERE relname='business'")
    out["biz_est_before"]=biz0; out["biz_est_after"]=biz1
    # which WIRED sources have NO rows yet (the stuck/empty ones)
    out["wired_no_rows"]=psql("SELECT count(*) FROM atlas.source_catalog sc WHERE sc.state='WIRED' AND NOT EXISTS (SELECT 1 FROM atlas.source_record sr WHERE sr.source_code=sc.source_key)")
    out["generic_timer"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'socrata-generic' | awk '{print $5,$NF}'; systemctl is-active atlas-socrata-generic.timer 2>/dev/null")
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/srcpull.json"%repo
    if tok:
        for _ in range(12):
            try:
                sha=None
                try:
                    rq=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(rq,timeout=15)).get("sha")
                except Exception: sha=None
                body={"message":"srcpull","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
                if sha: body["sha"]=sha
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=18); break
            except Exception: time.sleep(0.5+random.random()*2)
except Exception: pass
sys.exit(0)
